#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

using namespace std;

/**
 * @brief Solves the problem by checking all possible subsets using meet-in-the-middle or simply iterating over all 2^N subsets.
 * 
 * Given the constraint N <= 40, $2^{40}$ is too large for a full subset iteration (approx $10^{12}$).
 * However, the constraints on the values are small ($<= 10^4$). The key is the constraint $N \le 40$.
 *
 * Since $N$ is up to 40, we must use Meet-in-the-Middle (MITM).
 * Split nums into two halves, A and B, each of size up to 20. $2^{20} \approx 10^6$.
 * 
 * Let $S$ be the XOR sum of all elements in the final subset. We want $S = \text{target}$.
 * Let the subset be formed by $S_A \subset A$ and $S_B \subset B$. Then $S = \text{XOR}(\text{elements in } S_A) \oplus \text{XOR}(\text{elements in } S_B)$.
 * We want $\text{XOR}(S_A) \oplus \text{XOR}(S_B) = \text{target}$.
 * This means $\text{XOR}(S_B) = \text{target} \oplus \text{XOR}(S_A)$.
 * 
 * The number of elements removed is $N - |S|$, where $|S| = |S_A| + |S_B|$.
 * Minimizing removals means maximizing $|S|$.
 *
 * We need to store for each possible XOR sum achievable in the first half ($A$), the maximum size of a subset achieving that sum.
 * Similarly for the second half ($B$).
 * 
 * Let $mapA$ store: $\text{XOR\_sum} \rightarrow \text{max\_size}$ for subsets of $A$.
 * Let $mapB$ store: $\text{XOR\_sum} \rightarrow \text{max\_size}$ for subsets of $B$.
 */
long long solve(std::vector<long long> nums, long long target) {
    int N = nums.size();
    if (N == 0) {
        return (target == 0) ? 0 : -1;
    }

    int N1 = N / 2;
    int N2 = N - N1;

    // Map: XOR_sum -> Max_subset_size
    // Initialize with {0, 0} because the empty set results in XOR sum 0 and size 0.
    std::vector<std::pair<long long, int>> mapA_list;
    std::vector<std::pair<long long, int>> mapB_list;

    // --- Generate results for the first half (A) ---
    // Iterate through all 2^N1 subsets
    for (int i = 0; i < (1 << N1); ++i) {
        long long current_xor = 0;
        int current_size = 0;
        for (int j = 0; j < N1; ++j) {
            if ((i >> j) & 1) {
                current_xor ^= nums[j];
                current_size++;
            }
        }
        // Store the pair (XOR, size). If the same XOR is found, keep the larger size.
        mapA_list.push_back({current_xor, current_size});
    }

    // --- Generate results for the second half (B) ---
    // Iterate through all 2^N2 subsets
    for (int i = 0; i < (1 << N2); ++i) {
        long long current_xor = 0;
        int current_size = 0;
        for (int j = 0; j < N2; ++j) {
            if ((i >> j) & 1) {
                current_xor ^= nums[N1 + j];
                current_size++;
            }
        }
        mapB_list.push_back({current_xor, current_size});
    }

    // --- Consolidate maps to ensure we only keep max size for each XOR sum ---
    // Although the brute force structure above generates all, we need efficient lookups.
    // Let's use maps for clean consolidation, even though vectors of pairs could work if sorted.
    // Given the small size (max 2^20 entries), map operations are fine.

    std::vector<std::pair<long long, int>> consolidatedA;
    std::vector<std::pair<long long, int>> consolidatedB;

    // Consolidate A
    std::map<long long, int> finalA_map;
    for (const auto& p : mapA_list) {
        long long xor_val = p.first;
        int size = p.second;
        if (finalA_map.find(xor_val) == finalA_map.end() || size > finalA_map[xor_val]) {
            finalA_map[xor_val] = size;
        }
    }
    for (const auto& pair : finalA_map) {
        consolidatedA.push_back(pair);
    }

    // Consolidate B
    std::map<long long, int> finalB_map;
    for (const auto& p : mapB_list) {
        long long xor_val = p.first;
        int size = p.second;
        if (finalB_map.find(xor_val) == finalB_map.end() || size > finalB_map[xor_val]) {
            finalB_map[xor_val] = size;
        }
    }
    for (const auto& pair : finalB_map) {
        consolidatedB.push_back(pair);
    }

    // Sort B by XOR value for efficient lookup (though iterating map is also fast)
    // Sorting based on map keys is already implicit.

    // --- Search for the best combination ---
    int max_kept_size = -1;

    for (const auto& pairA : consolidatedA) {
        long long xorA = pairA.first;
        int sizeA = pairA.second;

        // We need xorB such that xorA ^ xorB = target
        // This means xorB = target ^ xorA
        long long required_xorB = target ^ xorA;

        if (finalB_map.count(required_xorB)) {
            int sizeB = finalB_map[required_xorB];
            int total_size = sizeA + sizeB;

            if (total_size > max_kept_size) {
                max_kept_size = total_size;
            }
        }
    }

    if (max_kept_size == -1) {
        return -1;
    } else {
        // Minimum removals = Total elements - Maximum kept elements
        return N - max_kept_size;
    }
}
