 * @brief Solves the problem of finding the minimum number of removals to achieve a target XOR sum.
 * 
 * Since the constraint on the length of nums is small (up to 40), we can use meet-in-the-middle or dynamic programming on subsets.
 * Given the nature of XOR sums, and the constraint N <= 40, a standard subset sum DP might be too slow (2^40).
 * Meet-in-the-middle is suitable for N <= 40 (2^20 complexity).
 */

long long solve(std::vector<long long> nums, long long target) {
    int n = nums.size();

    // Case 1: Empty set XOR sum is 0.
    if (target == 0) {
        // The minimum removals to get XOR sum 0 is 0 if the original XOR sum is 0,
        // or 1 if we remove all elements (leaving an empty set with XOR sum 0).
        // Since we want the *minimum* removals, we check the original XOR sum first.
        long long total_xor = 0;
        for (long long x : nums) {
            total_xor ^= x;
        }
        if (total_xor == 0) {
            return 0;
        }
        // If total_xor != 0, we need to see if we can achieve 0 by removing some elements.
        // If we remove all elements, the XOR sum is 0, requiring N removals.
        // We check the general logic below, but if target=0, 0 removals is best if possible.
    }

    // Meet-in-the-Middle approach for N <= 40
    int n1 = n / 2;
    int n2 = n - n1;

    // Generate all possible XOR sums for the first half (indices 0 to n1-1)
    // Store: {XOR_sum, minimum_removals_in_first_half_to_achieve_this_sum}
    // Since we are interested in the *remaining* elements, we store {XOR_sum, size_of_subset}
    // The number of removals is N1 - size_of_subset.

    // map1[xor_sum] = minimum number of elements *kept* from the first half 
    // to achieve xor_sum.
    std::vector<std::pair<long long, int>> sums1;
    // Iterate through all 2^n1 subsets of the first half
    for (int i = 0; i < (1 << n1); ++i) {
        long long current_xor = 0;
        int count = 0; // Number of elements kept
        for (int j = 0; j < n1; ++j) {
            if ((i >> j) & 1) {
                current_xor ^= nums[j];
                count++;
            }
        }
        sums1.push_back({current_xor, count});
    }

    // Sort and simplify sums1: for the same XOR sum, we only care about the maximum count (minimum removals)
    std::sort(sums1.begin(), sums1.end());
    std::vector<std::pair<long long, int>> best_sums1;
    int max_kept_count = -1;
    for (const auto& p : sums1) {
        if (p.second > max_kept_count) {
            best_sums1.push_back(p);
            max_kept_count = p.second;
        }
    }


    // Generate all possible XOR sums for the second half (indices n1 to n-1)
    std::vector<std::pair<long long, int>> sums2;
    // Iterate through all 2^n2 subsets of the second half
    for (int i = 0; i < (1 << n2); ++i) {
        long long current_xor = 0;
        int count = 0; // Number of elements kept
        for (int j = 0; j < n2; ++j) {
            if ((i >> j) & 1) {
                current_xor ^= nums[n1 + j];
                count++;
            }
        }
        sums2.push_back({current_xor, count});
    }

    // Sort and simplify sums2
    std::sort(sums2.begin(), sums2.end());
    std::vector<std::pair<long long, int>> best_sums2;
    max_kept_count = -1;
    for (const auto& p : sums2) {
        if (p.second > max_kept_count) {
            best_sums2.push_back(p);
            max_kept_count = p.second;
        }
    }


    long long min_removals = -1;

    // Iterate through all combinations from the two halves
    for (const auto& p1 : best_sums1) {
        long long xor1 = p1.first;
        int kept1 = p1.second;

        // We need xor1 ^ xor2 = target, so xor2 = target ^ xor1
        long long needed_xor2 = target ^ xor1;

        // Binary search (or use std::lower_bound) on best_sums2 to find the best match
        // We want to maximize kept2 such that best_sums2[k].first == needed_xor2

        // Find the first element whose XOR sum is >= needed_xor2
        auto it = std::lower_bound(best_sums2.begin(), best_sums2.end(), 
                                   std::make_pair(needed_xor2, -1));

        // If found, it points to the element with needed_xor2
        if (it != best_sums2.end() && it->first == needed_xor2) {
            int kept2 = it->second;
            int total_kept = kept1 + kept2;
            int total_removed = n - total_kept;

            if (min_removals == -1 || total_removed < min_removals) {
                min_removals = total_removed;
            }
        }
    }

    // Edge case: If target is 0, and the best combination found results in total_kept = 0, 
    // total_removed = N. This is a valid solution (empty set).
    // The initial check for target=0 handles the 0 removal case if the total XOR is 0.
    // The loop naturally handles the empty set case (0 kept1 + 0 kept2 = 0 kept, N removals).

    return min_removals;
}
